using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Gangorra/balança de peso (puzzle de peso — Etapa 6.1, mesma família da
/// WeightPlate, partilha GameWeightUtil): tem duas "pontas" (pontaA/pontaB,
/// Transforms filhos colocados nas extremidades do braço). Compara o peso em
/// cima de cada ponta e:
///
/// 1. Inclina gradualmente o braço para o lado mais leve subir e o mais
///    pesado descer (até "anguloMaximo").
/// 2. Se algo aterrar com força num lado (peso desse lado sobe de repente
///    "limiarImpacto" ou mais num único frame — ex: um objecto pesado é
///    largado ali), lança quem estiver no lado OPOSTO para cima:
///    "forcaLancamentoBase / peso de quem é lançado" — quanto mais leve,
///    mais alto voa; quanto mais pesado, menos é afectado.
///
/// Setup: cria 2 GameObjects filhos (plataformas das pontas, com Collider2D
/// sólido) e arrasta-os para "pontaA"/"pontaB". O pivô da rotação é a
/// posição deste GameObject (o "eixo" da gangorra).
/// </summary>
[DisallowMultipleComponent]
public class SeesawPlatform : MonoBehaviour
{
    [Header("Pontas")]
    [Tooltip("Plataforma na ponta A (gira com a gangorra).")]
    public Transform pontaA;

    [Tooltip("Plataforma na ponta B (gira com a gangorra).")]
    public Transform pontaB;

    [Tooltip("Raio usado para detectar quem está em cima de cada ponta.")]
    [Min(0.1f)] public float raioDeteccao = 0.6f;

    [Tooltip("Camadas verificadas ao detectar ocupantes (Player, Inimigos, Objectos com peso, etc).")]
    public LayerMask ocupantesLayer = ~0;

    [Header("Inclinação")]
    [Tooltip("Ângulo máximo (graus) para cada lado.")]
    [Range(1f, 89f)] public float anguloMaximo = 25f;

    [Tooltip("Diferença de peso necessária para atingir o ângulo máximo (menor = mais sensível).")]
    [Min(0.1f)] public float pesoParaAnguloMaximo = 5f;

    [Tooltip("Velocidade (graus/segundo) com que a gangorra se inclina até ao ângulo alvo.")]
    [Min(1f)] public float velocidadeInclinacao = 90f;

    [Header("Lançamento (Impulso)")]
    [Tooltip("Aumento súbito de peso (num único frame) considerado 'algo aterrou com força' — lança o lado oposto.")]
    [Min(0.05f)] public float limiarImpacto = 0.5f;

    [Tooltip("Força base do lançamento, dividida pelo peso de quem é lançado (mais leve = voa mais alto, mais pesado = quase não sente).")]
    [Min(0f)] public float forcaLancamentoBase = 10f;

    [Header("Eventos")]
    [Tooltip("Disparado com o Transform lançado (algo aterrou em B, lançou quem estava em A).")]
    public UnityEvent<Transform> onLancouLadoA;

    [Tooltip("Disparado com o Transform lançado (algo aterrou em A, lançou quem estava em B).")]
    public UnityEvent<Transform> onLancouLadoB;

    private float _currentAngle;
    private float _prevWeightA;
    private float _prevWeightB;

    private void FixedUpdate()
    {
        if (pontaA == null || pontaB == null) return;

        Vector2 oldPosA = pontaA.position;
        Vector2 oldPosB = pontaB.position;

        var collidersA = Physics2D.OverlapCircleAll(pontaA.position, raioDeteccao, ocupantesLayer);
        var collidersB = Physics2D.OverlapCircleAll(pontaB.position, raioDeteccao, ocupantesLayer);

        float weightA = SumWeight(collidersA);
        float weightB = SumWeight(collidersB);

        // Inclinação gradual: o lado mais pesado desce, o mais leve sobe.
        float targetAngle = Mathf.Clamp((weightB - weightA) / pesoParaAnguloMaximo, -1f, 1f) * anguloMaximo;
        _currentAngle = Mathf.MoveTowards(_currentAngle, targetAngle, velocidadeInclinacao * Time.fixedDeltaTime);
        transform.localRotation = Quaternion.Euler(0f, 0f, _currentAngle);

        // Lançamento: aumento súbito de peso num lado lança quem está no lado oposto.
        if (weightA - _prevWeightA >= limiarImpacto)
            Launch(collidersB, onLancouLadoB);
        else if (weightB - _prevWeightB >= limiarImpacto)
            Launch(collidersA, onLancouLadoA);

        _prevWeightA = weightA;
        _prevWeightB = weightB;

        // Arrasta quem está em cima conforme a rotação moveu cada ponta.
        CarryOccupants(collidersA, (Vector2)pontaA.position - oldPosA);
        CarryOccupants(collidersB, (Vector2)pontaB.position - oldPosB);
    }

    private static float SumWeight(Collider2D[] colliders)
    {
        float total = 0f;
        foreach (var c in colliders)
            total += GameWeightUtil.GetWeightOf(c);
        return total;
    }

    private void Launch(Collider2D[] colliders, UnityEvent<Transform> evt)
    {
        foreach (var c in colliders)
        {
            var rb = c.attachedRigidbody;
            if (rb == null) continue;

            // Quanto mais leve, maior a velocidade de lançamento; quanto mais pesado, menos é afectado.
            float weight = Mathf.Max(0.1f, GameWeightUtil.GetWeightOf(c));
            float launchSpeed = forcaLancamentoBase / weight;

            rb.linearVelocity = new Vector2(rb.linearVelocity.x, launchSpeed);
            evt?.Invoke(c.transform);
        }
    }

    private static void CarryOccupants(Collider2D[] colliders, Vector2 delta)
    {
        if (delta.sqrMagnitude <= 0f) return;

        foreach (var c in colliders)
        {
            var rb = c.attachedRigidbody;
            if (rb != null) rb.position += delta;
        }
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.yellow;
        if (pontaA != null) Gizmos.DrawWireSphere(pontaA.position, raioDeteccao);
        if (pontaB != null) Gizmos.DrawWireSphere(pontaB.position, raioDeteccao);
        Gizmos.color = Color.white;
        Gizmos.DrawWireSphere(transform.position, 0.1f);
    }
}
